%%%%%%%%%% Function fCmrCnfReadV02.m %%%%%%%%%%% Camera configuration reader, ver.2% Kei Nakamura% Created on Wednesday, November 7th 2007.% Modified on Monday, May 12th 2008.%% function [ttl,dat] = vrnInfRead(fname)% returns the name of the columns (title) and a matrix% containing the whole data of the log file.% ver.1: from vrnInfRead2.m% ttl: title of the data% dat: data% name: file name% nmb: number of elementsfunction [ttl,dat] = fCmrCnfReadV02(fname, nmb)  %function headerfid = fopen(fname);     % file open('name','permission')   lin1 = fgetl(fid);      % read first line (trash)for i=1:nmb    lin = fgetl(fid);    dbl = double(lin);    k = find(dbl==61);  % find '='      dat(i) = str2num(lin(k+1:end));    ttl{i} = lin(1:k-1);endfclose(fid);
